using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: default ToolStrip/StatusStrip renderer changed
        // from Professional to System. Restore previous appearance explicitly.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }

    public string? DisplayName { get; set; }
    public int MaxItems { get; set; }
}

public class MyControlEditor : UITypeEditor
{
    public override object? EditValue(ITypeDescriptorContext? context,
        IServiceProvider provider, object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null)
            return value;

        using var dropDown = BuildDropDown(value);

        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
        // when passed null. Always guard the call.
        if (dropDown is not null)
        {
            editorService.DropDownControl(dropDown);
            value = dropDown.SelectedItem;
        }

        return value;
    }

    private static ListBox? BuildDropDown(object? currentValue)
    {
        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { "Option1", "Option2", "Option3" });
        if (currentValue is not null)
            listBox.SelectedItem = currentValue;
        return listBox;
    }
}

